#!/bin/bash\n\n# Container Installation Verification Script\n# Checks all container-related files are in place\n\necho \"\"\necho \"═══════════════════════════════════════════════════════════════════════\"\necho \"  TikTok Clone - Container Tools Installation Verification\"\necho \"═══════════════════════════════════════════════════════════════════════\"\necho \"\"\n\nerrors=0\nwarnings=0\nsuccess=0\n\ncheck_file() {\n    local file=$1\n    local description=$2\n    \n    if [ -f \"$file\" ] || [ -d \"$file\" ]; then\n        echo \"✓ $description\"\n        echo \"  Path: $file\"\n        ((success++))\n    else\n        echo \"✗ MISSING: $description\"\n        echo \"  Path: $file\"\n        ((errors++))\n    fi\n}\n\necho \"[1] Core Docker Files\"\ncheck_file \"docker-compose.yml\" \"Docker Compose main config\"\ncheck_file \"docker-compose.prod.yml\" \"Production overrides\"\ncheck_file \"apps/server/Dockerfile\" \"Server production Dockerfile\"\necho \"\"\n\necho \"[2] Container Management Tools\"\ncheck_file \"container-tools\" \"Container tools directory\"\ncheck_file \"container-tools/manage.sh\" \"Linux/Mac management script\"\ncheck_file \"container-tools/manage.cmd\" \"Windows management script\"\necho \"\"\n\necho \"[3] Nginx Configuration\"\ncheck_file \"nginx\" \"Nginx directory\"\ncheck_file \"nginx/nginx.conf\" \"Main Nginx configuration\"\ncheck_file \"nginx/conf.d\" \"Nginx conf.d directory\"\ncheck_file \"nginx/conf.d/default.conf\" \"Default Nginx config\"\necho \"\"\n\necho \"[4] Monitoring & Logging\"\ncheck_file \"monitoring\" \"Monitoring directory\"\ncheck_file \"monitoring/prometheus.yml\" \"Prometheus configuration\"\necho \"\"\n\necho \"[5] Database & Scripts\"\ncheck_file \"scripts\" \"Scripts directory\"\ncheck_file \"scripts/init-db.sql\" \"Database initialization script\"\necho \"\"\n\necho \"[6] Configuration Files\"\ncheck_file \".env.production\" \"Production environment template\"\ncheck_file \".env.example\" \"Development environment template\"\necho \"\"\n\necho \"[7] Documentation\"\ncheck_file \"CONTAINER_TOOLS_GUIDE.md\" \"Container tools guide\"\ncheck_file \"docker-network-guide.md\" \"Docker networking guide\"\ncheck_file \"CONTAINER_INSTALLATION_SUMMARY.md\" \"Installation summary\"\necho \"\"\n\necho \"═══════════════════════════════════════════════════════════════════════\"\necho \"\"\necho \"Verification Results:\"\necho \"  ✓ Found:    $success items\"\necho \"  ✗ Missing:  $errors items\"\necho \"  ⚠ Warnings: $warnings items\"\necho \"\"\n\nif [ $errors -eq 0 ]; then\n    echo \"✅ All container tools successfully installed!\"\n    echo \"\"\n    echo \"Next steps:\"\n    echo \"  1. Make scripts executable:\"\n    echo \"     chmod +x container-tools/manage.sh\"\n    echo \"\"\n    echo \"  2. Generate SSL certificates (optional):\"\n    echo \"     mkdir -p nginx/ssl\"\n    echo \"     openssl req -x509 -newkey rsa:4096 -keyout nginx/ssl/key.pem \\\\\"\n    echo \"       -out nginx/ssl/cert.pem -days 365 -nodes\"\n    echo \"\"\n    echo \"  3. Start all containers:\"\n    echo \"     ./container-tools/manage.sh up\"\n    echo \"\"\n    echo \"  4. Verify installation:\"\n    echo \"     ./container-tools/manage.sh status\"\n    echo \"\"\n    echo \"  5. Run health checks:\"\n    echo \"     ./container-tools/manage.sh health-check\"\n    echo \"\"\n    echo \"Documentation:\"\n    echo \"  - Quick Start: CONTAINER_INSTALLATION_SUMMARY.md\"\n    echo \"  - Full Guide:  CONTAINER_TOOLS_GUIDE.md\"\n    echo \"  - Networking: docker-network-guide.md\"\nelse\n    echo \"❌ Installation incomplete. Missing $errors items.\"\n    echo \"Please ensure all files are created properly.\"\nfi\n\necho \"\"\necho \"═══════════════════════════════════════════════════════════════════════\"\necho \"\"\n